import Image from '../Assets/Portrait2.jpg'
import book1 from '../Assets/chapter-house-dune.jpg'
import book2 from '../Assets/fingerprint_of_gods.jpg'
import book3 from '../Assets/economics.jpg'

import Box from '@mui/material/Box';
import Grid from '@mui/material/Grid';
import Typography from '@mui/material/Typography';
import Container from '@mui/material/Container';
const books = [book1, book2, book3]

const gridItem = (name, path) => {
    return (
        <Container
          sx={{
            width: '15rem',
            height: '8rem',
            display: 'flex',
            justifyContent: 'center',
            alignItems: 'center',
            bgcolor: '#292929',
            m: 'auto',
            p: 1,
            borderRadius: '10px',
            transition: '0.5s',
            '&:hover': { transform: 'scale(1.05)' }
          }}
        >
          <Box
            component='img'
            src={path}
            alt={`${name} logo`}
            height='5rem'
            mr={2}
          />
          <Typography color='#e1e1e1'>{name}</Typography>
        </Container>
    );
};



function About() {
    console.log(books)
    return (
        <Container 
        id='intro'
        maxWidth='none'
        sx={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-evenly',
          mt: '25vh',
          mb: '25vh',
          width: '75%',
        }}
        >
           <Box
            component='img'
            src={Image}
            alt='headshot of Kyle Schneider'
            sx={{
              height: '35%',
              width: '35%',
              borderRadius: '10px',
            }}
          />
          <Box textAlign='center'>
            <Typography variant='h1'>Kyle Schneider</Typography>
            <Typography variant='h2'>Software Developer</Typography>
            <Typography>
              I am a software developer with a passion for learning and creating. 
              <br />
              I use my background in mathematics and science to solve problems and build applications.
            </Typography>
          </Box>

          <Box>
                {/* Books */}
                <Typography 
                  variant='h3' 
                  textAlign='center'
                  sx={{ mt: '5vh' }}
                >
                  Books I'm Reading
                </Typography>
                <Box 
                  display='flex' 
                  flexDirection='row' 
                  justifyContent='center'  
                  alignItems='center'
                >
                    {books.map((book, index) => {
                        return (
                            <Box 
                              key={index}
                              component='img'   
                              src={book} 
                              alt='' 
                              sx={{
                                height: '18vw',
                                width: '12vw',
                                mx: 2
                              }}
                            />
                        );
                    })}
                </Box>
            </Box>


        </Container>
    )
}
export default About
